"use client";

import { useState } from "react";
import { createClient } from "@/lib/supabase/client";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Send, CheckCircle2, Loader2 } from "lucide-react";

export function ContactForm() {
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState(false);
  const supabase = createClient();

  const handleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    setLoading(true);

    const formData = new FormData(e.currentTarget);
    const data = {
      nombre: formData.get("nombre"),
      email: formData.get("email"),
      asunto: formData.get("asunto"),
      mensaje: formData.get("mensaje"),
    };

    const { error } = await supabase.from("mensajes_contacto").insert([data]);

    if (!error) {
      setSuccess(true);
      (e.target as HTMLFormElement).reset();
    } else {
      alert("Hubo un error al enviar: " + error.message);
    }
    setLoading(false);
  };

  if (success) {
    return (
      <div className="text-center py-20 space-y-6 animate-in zoom-in duration-500">
        <div className="w-20 h-20 bg-green-100 text-green-600 rounded-full flex items-center justify-center mx-auto">
          <CheckCircle2 className="w-10 h-10" />
        </div>
        <h3 className="text-3xl font-black uppercase tracking-tighter">¡Mensaje Enviado!</h3>
        <p className="text-zinc-500 max-w-xs mx-auto">Tu consulta ya está en manos de la secretaría del club. Te responderemos pronto.</p>
        <Button 
          variant="outline" 
          onClick={() => setSuccess(false)}
          className="rounded-none border-zinc-200 uppercase font-black tracking-widest"
        >
          Enviar otro mensaje
        </Button>
      </div>
    );
  }

  return (
    <form onSubmit={handleSubmit} className="space-y-8">
      <div className="grid md:grid-cols-2 gap-6">
        <div className="space-y-2">
          <label className="text-[10px] font-black uppercase tracking-widest text-zinc-400 ml-4">Nombre Completo</label>
          <Input name="nombre" required className="rounded-2xl bg-zinc-50 border-zinc-100 h-14" placeholder="Ej: Juan Pérez" />
        </div>
        <div className="space-y-2">
          <label className="text-[10px] font-black uppercase tracking-widest text-zinc-400 ml-4">Email de Contacto</label>
          <Input name="email" type="email" required className="rounded-2xl bg-zinc-50 border-zinc-100 h-14" placeholder="juan@ejemplo.com" />
        </div>
      </div>

      <div className="space-y-2">
        <label className="text-[10px] font-black uppercase tracking-widest text-zinc-400 ml-4">Asunto</label>
        <Input name="asunto" className="rounded-2xl bg-zinc-50 border-zinc-100 h-14" placeholder="¿En qué podemos ayudarte?" />
      </div>

      <div className="space-y-2">
        <label className="text-[10px] font-black uppercase tracking-widest text-zinc-400 ml-4">Mensaje</label>
        <Textarea name="mensaje" required className="rounded-2xl bg-zinc-50 border-zinc-100 min-h-[150px] p-6" placeholder="Escribí tu consulta aquí..." />
      </div>

      <Button 
        type="submit" 
        disabled={loading}
        className="w-full bg-red-600 hover:bg-zinc-900 text-white rounded-none font-black uppercase tracking-widest py-8 transition-all gap-3 shadow-xl shadow-red-600/20"
      >
        {loading ? <Loader2 className="animate-spin w-5 h-5" /> : (
          <>
            Enviar Consulta <Send className="w-5 h-5" />
          </>
        )}
      </Button>
    </form>
  );
}